    Movie movies[100]; // Assuming a maximum of 100 movies
    int n = 0;

    printf("Enter movie title: ");
    fgets(movies[n].title, MAX_TITLE_LENGTH, stdin);
    movies[n].title[strcspn(movies[n].title, "\n")] = 0; // Remove trailing newline

    printf("Enter movie director: ");
    fgets(movies[n].director, MAX_DIRECTOR_LENGTH, stdin);
    movies[n].director[strcspn(movies[n].director, "\n")] = 0; // Remove trailing newline

